+sensor_info metadata_from_json(const std::string & json_file)
+{
+  std::stringstream buf{};
+  std::ifstream ifs{};
+  ifs.open(json_file);
+  buf << ifs.rdbuf();
+  ifs.close();
+
+  if (!ifs) {
+    std::stringstream ss;
+    ss << "Failed to read metadata file: " << json_file;
+    throw std::runtime_error(ss.str());
+  }
+
+  return parse_metadata(buf.str());
+}
