+version version_of_string(const std::string & s)
+{
+  std::istringstream is{s};
+  char c1, c2, c3;
+  version v;
+
+  is >> c1 >> v.major >> c2 >> v.minor >> c3 >> v.patch;
+
+  if (is && c1 == 'v' && c2 == '.' && c3 == '.') {
+    return v;
+  } else {
+    return invalid_version;
+  }
+}
